from crewai import Agent, Task, Crew
from collections import defaultdict

def detect_delegation_loops(crew):
    delegation_graph = defaultdict(list)
    for task in crew.tasks:
        if task.assignee and task.context:
            # Track who delegated to whom
            delegation_graph[task.assignee.name].append(task.description[:50])

    # Detect cycles
    visited = set()
    rec_stack = set()

    def has_cycle(node):
        visited.add(node)
        rec_stack.add(node)
        for neighbor in delegation_graph[node]:
            if neighbor not in visited:
                if has_cycle(neighbor):
                    return True
            elif neighbor in rec_stack:
                return True
        rec_stack.remove(node)
        return False

    for agent in delegation_graph:
        if agent not in visited:
            if has_cycle(agent):
                return {'issue': 'DELEGATION_LOOP', 'agents': list(delegation_graph.keys())}
    return None

