from crewai import Task

def create_validated_task(description: str, expected_memory_keys: list, agent):
    def validate_memory(context):
        missing_keys = [k for k in expected_memory_keys if k not in context]
        if missing_keys:
            raise ValueError(f'Missing memory keys: {missing_keys}')
        return context

    return Task(
        description=f"""{description}
        Validate you have required context: {expected_memory_keys}
        Current memory keys: {{list(context.keys())}}""",
        expected_output='Validated task completion with consistent memory',
        agent=agent,
        context=[validate_memory],
        max_iterations=3  # Prevent loops
    )

